// VSOP87 evaluation helper
function _vsop87Lon(data, tau) {
  function sumSeries(terms) {
    let s = 0;
    for (const [A, B, C] of terms) s += A * Math.cos(B + C * tau);
    return s;
  }
  const L = (sumSeries(data.L0)
           + sumSeries(data.L1) * tau
           + sumSeries(data.L2) * tau * tau) / 1e8; // radians
  return mod360(toDeg(L));
}

// Earth heliocentric longitude (needed for geocentric conversion)
function _earthHelioLon(tau) {
  return _vsop87Lon(VSOP87_EARTH_L, tau);
}

// Earth heliocentric radius (AU) — approximate via R-series
// We use a simplified R for the geocentric conversion direction correction.
// The dominant term is enough for sign-level accuracy.
function _earthHelioR(tau) {
  // R0 dominant terms from VSOP87
  const R0terms = [
    [100013989.0, 0.0,        0.0        ],
    [  1670700.0, 3.09846350, 6283.075850],
    [    13956.0, 3.05524110,12566.151700],
    [     3084.0, 5.19846680,77713.771470],
    [     1628.0, 1.17387580, 5753.384910],
    [     1576.0, 2.84685210, 7860.419390],
    [      925.0, 5.45292300,11506.769770],
    [      542.0, 4.56441200, 3930.209690],
    [      472.0, 3.66100690, 5884.926850],
    [      346.0, 0.96445100, 5507.553240],
    [      329.0, 5.89983800, 5223.693940],
    [      307.0, 0.29867500,  553.569400],
  ];
  let R = 0;
  for (const [A, B, C] of R0terms) R += A * Math.cos(B + C * tau);
  return R / 1e8; // AU
}

function _planetHelioR(planet, tau) {
  // Approximate heliocentric distances (AU) using mean values for outer planets
  // For inner planets we return rough semi-major axis
  const sma = { mercury:0.387, venus:0.723, mars:1.524, jupiter:5.203,
                saturn:9.537, uranus:19.19, neptune:30.07, pluto:39.48 };
  return sma[planet] || 1.0;
}

// Full geocentric ecliptic longitude via vector subtraction (simplified planar)
function geocentricPlanetLongitude(planet, jd) {
  const p = planet.toLowerCase();
  if (p === 'sun') return sunPosition(jd).lon;
  if (p === 'moon') return moonPosition(jd).lon;

  const tau = (jd - 2451545.0) / 365250; // Julian millennia

  const data = VSOP87[p];
  if (!data) return 0;

  const helioLon_p   = _vsop87Lon(data, tau);
  const helioLon_e   = _earthHelioLon(tau);
  const R_p          = _planetHelioR(p, tau);
  const R_e          = _earthHelioR(tau);

  // Rectangular heliocentric coordinates (planar, ecliptic)
  const x_p = R_p * Math.cos(toRad(helioLon_p));
  const y_p = R_p * Math.sin(toRad(helioLon_p));
  const x_e = R_e * Math.cos(toRad(helioLon_e));
  const y_e = R_e * Math.sin(toRad(helioLon_e));

  // Geocentric direction
  const dx = x_p - x_e;
  const dy = y_p - y_e;
  return mod360(toDeg(Math.atan2(dy, dx)));
}

// ---------------------------------------------------------------------------
// 9. Ascendant
// ---------------------------------------------------------------------------

function ascendant(lst, lat, eps) {
  // ARMC-based oblique ascension formula (Meeus Ch 14)
  const lstR = toRad(lst);
  const latR = toRad(lat);
  const epsR = toRad(eps);

  const y = -Math.cos(lstR);
  const x = Math.sin(epsR) * Math.tan(latR) + Math.cos(epsR) * Math.sin(lstR);
  let asc = toDeg(Math.atan2(y, x));
  return mod360(asc);
}

// ---------------------------------------------------------------------------
// 10. Midheaven (MC)
// ---------------------------------------------------------------------------

function midheaven(lst, eps) {
  const lstR = toRad(lst);
  const epsR = toRad(eps);
  let mc = toDeg(Math.atan2(Math.sin(lstR), Math.cos(lstR) * Math.cos(epsR)));
  return mod360(mc);
}

// ---------------------------------------------------------------------------
// 11. Placidus Houses
// ---------------------------------------------------------------------------

function placidusHouses(mc_lon, asc_lon, lat, eps) {
  const latR = toRad(lat);
  const epsR = toRad(eps);

  // Iterative Placidus cusp for house cusps between MC and ASC
  // fraction = 1/3 or 2/3 of the nocturnal/diurnal semi-arc
  function placidusInterp(startLon, fraction) {
    let cusp = mod360(startLon + fraction * 90);
    for (let iter = 0; iter < 30; iter++) {
      const cr = toRad(cusp);
      const sinDec = Math.sin(epsR) * Math.sin(cr);
      // clamp to avoid asin domain errors
      const sinDecClamped = Math.max(-1, Math.min(1, sinDec));
      const dec = Math.asin(sinDecClamped);
      const tanDecTanLat = Math.tan(dec) * Math.tan(latR);
      if (Math.abs(tanDecTanLat) > 1) break; // circumpolar
      const hourAngle = toDeg(Math.acos(-tanDecTanLat));
      const newCusp = mod360(mc_lon + fraction * hourAngle);
      if (Math.abs(newCusp - cusp) < 0.00001) { cusp = newCusp; break; }
      cusp = newCusp;
    }
    return mod360(cusp);
  }

  const H1  = asc_lon;
  const H10 = mc_lon;
  const H11 = placidusInterp(mc_lon, 1/3);
  const H12 = placidusInterp(mc_lon, 2/3);
  const H2  = mod360(H12 + 180);
  const H3  = mod360(H11 + 180);
  const H4  = mod360(H10 + 180);
  const H5  = mod360(H3  + 180);
  const H6  = mod360(H2  + 180);
  const H7  = mod360(H1  + 180);
  const H8  = mod360(H12);
  const H9  = mod360(H11);

  return [H1, H2, H3, H4, H5, H6, H7, H8, H9, H10, H11, H12];
}

// ---------------------------------------------------------------------------
// 12. Aspects
// ---------------------------------------------------------------------------

const ASPECT_DEFS = [
  { name: 'conjunction',    angle:   0, orb: 8 },
  { name: 'opposition',     angle: 180, orb: 8 },
  { name: 'trine',          angle: 120, orb: 7 },
  { name: 'square',         angle:  90, orb: 7 },
  { name: 'sextile',        angle:  60, orb: 5 },
  { name: 'quincunx',       angle: 150, orb: 3 },
  { name: 'semisquare',     angle:  45, orb: 2 },
  { name: 'sesquiquadrate', angle: 135, orb: 2 },
  { name: 'semisextile',    angle:  30, orb: 2 },
  { name: 'quintile',       angle:  72, orb: 1 },
];

// Approximate mean daily motion in degrees/day for applying detection
const DAILY_MOTION = {
  sun: 0.9856, moon: 13.176, mercury: 1.383, venus: 1.202, mars: 0.524,
  jupiter: 0.0831, saturn: 0.0335, uranus: 0.0117, neptune: 0.0060,
  pluto: 0.0040, chiron: 0.014, northnode: -0.053, southnode: 0.053,
  asc: 0, mc: 0
};

function calculateAspects(positions, jd) {
  const aspects = [];
  const keys = Object.keys(positions);

  for (let i = 0; i < keys.length; i++) {
    for (let j = i + 1; j < keys.length; j++) {
      const p1 = keys[i];
      const p2 = keys[j];
      const lon1 = typeof positions[p1] === 'object' ? positions[p1].longitude : positions[p1];
      const lon2 = typeof positions[p2] === 'object' ? positions[p2].longitude : positions[p2];

      let diff = Math.abs(lon1 - lon2);
      if (diff > 180) diff = 360 - diff;

      for (const asp of ASPECT_DEFS) {
        const orb = Math.abs(diff - asp.angle);
        if (orb <= asp.orb) {
          // Applying: the orb is closing (faster planet approaching exact aspect)
          let applying = false;
          const dm1 = DAILY_MOTION[p1.toLowerCase()] || 0;
          const dm2 = DAILY_MOTION[p2.toLowerCase()] || 0;
          const relSpeed = dm1 - dm2;
          const signedDiff = lon1 - lon2;
          // Normalise signed difference to -180..180
          const sd = ((signedDiff % 360) + 540) % 360 - 180;
          applying = (relSpeed * sd) < 0;
          aspects.push({ planet1: p1, planet2: p2, aspect: asp.name, orb: +orb.toFixed(4), applying });
        }
      }
    }
  }
  return aspects;
}

// ---------------------------------------------------------------------------
// 13. Retrograde
// ---------------------------------------------------------------------------

function isRetrograde(planet, jd) {
  const p = planet.toLowerCase();
  if (p === 'sun' || p === 'moon' || p === 'northnode' || p === 'southnode') return false;
  const lon1 = geocentricPlanetLongitude(p, jd);
  const lon2 = geocentricPlanetLongitude(p, jd + 1);
  let motion = lon2 - lon1;
  if (motion > 180)  motion -= 360;
  if (motion < -180) motion += 360;
  return motion < 0;
}

// ---------------------------------------------------------------------------
// Mean Lunar Node and Chiron
// ---------------------------------------------------------------------------

function lunarNode(jd) {
  const T = (jd - 2451545.0) / 36525;
  return mod360(125.04452 - 1934.136261*T + 0.0020708*T*T + T*T*T/450000);
}

function chironPosition(jd) {
  // Chiron (2060) — approximate mean longitude using orbital period 50.42 yr
  const epoch_jd  = 2451545.0; // J2000.0
  const epoch_lon = 209.39;    // approximate ecliptic longitude at J2000.0 (degrees)
  const period    = 50.42 * 365.25; // days
  return mod360(epoch_lon + 360 * (jd - epoch_jd) / period);
}

// ---------------------------------------------------------------------------
// Sign helpers
// ---------------------------------------------------------------------------

const SIGNS = [
  'Aries','Taurus','Gemini','Cancer','Leo','Virgo',
  'Libra','Scorpio','Sagittarius','Capricorn','Aquarius','Pisces'
];

function signOf(lon) {
  return SIGNS[Math.floor(mod360(lon) / 30)];
}

function degreeInSign(lon) {
  return mod360(lon) % 30;
}

const ELEMENTS = {
  Aries:'Fire',  Leo:'Fire',  Sagittarius:'Fire',
  Taurus:'Earth',Virgo:'Earth',Capricorn:'Earth',
  Gemini:'Air',  Libra:'Air', Aquarius:'Air',
  Cancer:'Water',Scorpio:'Water',Pisces:'Water'
};

const MODALITIES = {
  Aries:'Cardinal',Cancer:'Cardinal',Libra:'Cardinal',Capricorn:'Cardinal',
  Taurus:'Fixed', Leo:'Fixed',  Scorpio:'Fixed',  Aquarius:'Fixed',
  Gemini:'Mutable',Virgo:'Mutable',Sagittarius:'Mutable',Pisces:'Mutable'
};

const SIGN_RULERS = {
  Aries:'mars',      Taurus:'venus',   Gemini:'mercury', Cancer:'moon',
  Leo:'sun',         Virgo:'mercury',  Libra:'venus',    Scorpio:'pluto',
  Sagittarius:'jupiter', Capricorn:'saturn', Aquarius:'uranus', Pisces:'neptune'
};

// ---------------------------------------------------------------------------
// 14. calculateNatalChart — main entry point
// ---------------------------------------------------------------------------

function calculateNatalChart(year, month, day, hour, minute, lat, lon) {
  const jd  = julianDay(year, month, day, hour, minute, 0);
  const T   = (jd - 2451545.0) / 36525;
  const eps = obliquityOfEcliptic(T);
  const lst = localSiderealTime(jd, lon);

  const sunPos  = sunPosition(jd);
  const moonPos = moonPosition(jd);

  const outerPlanets = ['mercury','venus','mars','jupiter','saturn','uranus','neptune','pluto'];
  const rawPositions = {};
  for (const p of outerPlanets) {
    rawPositions[p] = geocentricPlanetLongitude(p, jd);
  }
  rawPositions.sun   = sunPos.lon;
  rawPositions.moon  = moonPos.lon;
  rawPositions.chiron     = chironPosition(jd);
  rawPositions.northNode  = lunarNode(jd);
  rawPositions.southNode  = mod360(rawPositions.northNode + 180);

  const ascDeg = ascendant(lst, lat, eps);
  const mcDeg  = midheaven(lst, eps);
  rawPositions.asc = ascDeg;
  rawPositions.mc  = mcDeg;

  const houses = placidusHouses(mcDeg, ascDeg, lat, eps);

  // Build detailed position objects
  const retroPlanets = new Set(['mercury','venus','mars','jupiter','saturn','uranus','neptune','pluto','chiron']);
  const positions = {};
  for (const [name, longitude] of Object.entries(rawPositions)) {
    positions[name] = {
      longitude,
      sign:      signOf(longitude),
      degree:    +degreeInSign(longitude).toFixed(4),
      retrograde: retroPlanets.has(name) ? isRetrograde(name, jd) : false,
    };
  }

  // Aspect grid
  const aspects = calculateAspects(rawPositions, jd);

  // Dominant element & modality (core 7 planets)
  const elementCount  = { Fire:0, Earth:0, Air:0, Water:0 };
  const modalityCount = { Cardinal:0, Fixed:0, Mutable:0 };
  for (const p of ['sun','moon','mercury','venus','mars','jupiter','saturn']) {
    const sign = positions[p].sign;
    elementCount[ELEMENTS[sign]]++;
    modalityCount[MODALITIES[sign]]++;
  }
  const dominantElement  = Object.entries(elementCount).sort((a,b) => b[1]-a[1])[0][0];
  const dominantModality = Object.entries(modalityCount).sort((a,b) => b[1]-a[1])[0][0];

  const ascSign    = signOf(ascDeg);
  const chartRuler = SIGN_RULERS[ascSign];

  return {
    jd,
    positions,
    houses,
    aspects,
    dominantElement,
    dominantModality,
    chartRuler,
    ascendant: ascDeg,
    midheaven: mcDeg,
    obliquity: eps,
  };
}

